// BMAD Email Processing - BUILD Phase
const emailData = $input.first().json;

// Extract email components
const email = {
  from: emailData.from || '',
  to: emailData.to || '',
  subject: emailData.subject || '',
  body: emailData.body || '',
  html: emailData.html || '',
  received_at: new Date().toISOString(),
  message_id: emailData.messageId || '',
  thread_id: emailData.threadId || ''
};

// Clean and normalize data
email.subject = email.subject.trim();
email.body = email.body.trim();
email.html = email.html.trim();

// Extract sender information
const fromMatch = email.from.match(/([^<]+)<([^>]+)>/) || [null, email.from, email.from];
email.sender_name = fromMatch[1]?.trim() || 'Unknown';
email.sender_email = fromMatch[2]?.trim() || email.from;

// Determine persona based on email content
let persona = 'mary'; // Default to customer success
let confidence = 0.5;

// Persona identification logic
const subject = email.subject.toLowerCase();
const body = email.body.toLowerCase();
const content = subject + ' ' + body;

// Customer Success (Mary)
if (content.includes('onboarding') || content.includes('support') || content.includes('help') || 
    content.includes('customer') || content.includes('success')) {
  persona = 'mary';
  confidence = 0.95;
}
// Technical Support (John)
else if (content.includes('error') || content.includes('bug') || content.includes('api') || 
         content.includes('integration') || content.includes('technical') || content.includes('system')) {
  persona = 'john';
  confidence = 0.98;
}
// Business Development (Winston)
else if (content.includes('partnership') || content.includes('inquiry') || content.includes('proposal') || 
         content.includes('business') || content.includes('sales') || content.includes('quote')) {
  persona = 'winston';
  confidence = 0.92;
}
// Marketing (Sarah)
else if (content.includes('campaign') || content.includes('content') || content.includes('social') || 
         content.includes('marketing') || content.includes('brand') || content.includes('promotion')) {
  persona = 'sarah';
  confidence = 0.90;
}
// Operations (Alex)
else if (content.includes('process') || content.includes('workflow') || content.includes('optimization') || 
         content.includes('operation') || content.includes('efficiency')) {
  persona = 'alex';
  confidence = 0.94;
}
// Finance (Quinn)
else if (content.includes('invoice') || content.includes('payment') || content.includes('financial') || 
         content.includes('billing') || content.includes('money') || content.includes('cost')) {
  persona = 'quinn';
  confidence = 0.96;
}

// Determine urgency
let urgency = 'normal';
if (content.includes('urgent') || content.includes('asap') || content.includes('emergency') || 
    content.includes('critical') || content.includes('immediate')) {
  urgency = 'high';
}

// Generate response template
const responseData = {
  email: email,
  persona: persona,
  confidence: confidence,
  urgency: urgency,
  requires_human: urgency === 'high' || confidence < 0.7,
  processing_status: 'received'
};

return [
  {
    json: responseData
  }
];

